// ═══ فحص الإعدادات وتحديد الوجبات التي حان وقتها ═══
const config = $('Configuration').first().json;
const raw = $input.first().json;

// هل التشغيل يدوي؟
let isManual = false;
try { $('Manual Trigger').first(); isManual = true; } catch(e) {}

if (isManual) console.log('🔧 تشغيل يدوي — تجاوز فحص الساعة');

// تحويل Firestore format إلى JSON عادي
const fields = raw.fields || {};
const enabled = fields.enabled?.booleanValue === true;

if (!enabled) {
  console.log('⏸️ التذكير التلقائي معطّل');
  return [];
}

// استخراج الوجبات
const batchesArray = fields.batches?.arrayValue?.values || [];
if (batchesArray.length === 0) {
  console.log('⚠️ لا توجد وجبات مجدولة');
  return [];
}

// حساب الوقت الحالي بتوقيت بغداد (UTC+3)
const now = new Date();
const baghdadOffset = 3 * 60;
const baghdadNow = new Date(now.getTime() + (baghdadOffset + now.getTimezoneOffset()) * 60000);
const currentHour = baghdadNow.getHours();
const currentMinute = baghdadNow.getMinutes();
const todayKey = `${baghdadNow.getFullYear()}-${String(baghdadNow.getMonth()+1).padStart(2,'0')}-${String(baghdadNow.getDate()).padStart(2,'0')}`;

console.log(`🕐 الوقت الحالي (بغداد): ${currentHour}:${String(currentMinute).padStart(2,'0')}`);
console.log(`📅 التاريخ: ${todayKey}`);

// فحص كل وجبة
const dueBatches = [];
for (const bv of batchesArray) {
  const batchFields = bv.mapValue?.fields || {};
  const id = batchFields.id?.stringValue || '';
  const hour = Number(batchFields.hour?.integerValue || 0);
  const minute = Number(batchFields.minute?.integerValue || 0);
  const days = Number(batchFields.days?.integerValue || 0);
  const batchEnabled = batchFields.enabled?.booleanValue !== false;

  if (!batchEnabled) continue;

  // فحص الساعة فقط في التشغيل التلقائي
  if (!isManual && currentHour !== hour) continue;

  dueBatches.push({
    id,
    hour,
    minute,
    days,
    todayKey,
    tenantId: config.tenantId,
    firebaseProject: config.firebaseProject,
    ftthUsername: config.ftthUsername,
    ftthPassword: config.ftthPassword,
    managerPhone: config.managerPhone,
    templateName: config.templateName
  });
}

if (dueBatches.length === 0) {
  console.log('⏳ لم يحن وقت أي وجبة');
  return [];
}

console.log(`🔔 ${dueBatches.length} وجبة/وجبات حان وقتها!`);
return dueBatches.map(b => ({ json: b }));

// ═══ تمرير مباشر — نافذة الوقت في Check Schedule تمنع التكرار ═══
const batch = $('Check Schedule').first().json;
return [{ json: batch }];

