// ═══ حساب نطاق التاريخ حسب الوجبة (بتوقيت بغداد) ═══
const batch = $('Filter Already Sent').first().json;
const token = $json.access_token;
const days = batch.days;

// حساب بتوقيت بغداد UTC+3
const now = new Date();
const baghdadOffset = 3 * 60;
const baghdadNow = new Date(now.getTime() + (baghdadOffset + now.getTimezoneOffset()) * 60000);

// بداية اليوم المستهدف
const targetDate = new Date(baghdadNow);
targetDate.setDate(targetDate.getDate() + days);

const fromBaghdad = new Date(
  targetDate.getFullYear(),
  targetDate.getMonth(),
  targetDate.getDate(),
  0, 0, 0
);
const toBaghdad = new Date(
  targetDate.getFullYear(),
  targetDate.getMonth(),
  targetDate.getDate(),
  23, 59, 59
);

// تحويل لـ UTC
const fromUTC = new Date(fromBaghdad.getTime() - baghdadOffset * 60000).toISOString();
const toUTC = new Date(toBaghdad.getTime() - baghdadOffset * 60000).toISOString();

console.log(`📅 جلب المنتهيين: ${fromUTC} → ${toUTC}`);

return [{
  json: {
    access_token: token,
    fromExpirationDate: fromUTC,
    toExpirationDate: toUTC,
    pageNumber: 1,
    pageSize: 150,
    batch: batch
  }
}];

// ═══ استخراج بيانات المشتركين + Pagination ═══
const store = $getWorkflowStaticData('global');
const data = $input.first().json;
const items = data.items || [];
const batch = $('Calculate Date Range').first().json.batch;
const token = $('Calculate Date Range').first().json.access_token;
const pageSize = 150;

// تتبع رقم الصفحة
if (!store.currentPage) store.currentPage = 1;
if (!store.subscribers) store.subscribers = [];

console.log(`📄 صفحة ${store.currentPage}: ${items.length} عنصر`);

// تخزين المشتركين
for (const row of items) {
  store.subscribers.push({
    customer_id: row.customer?.id,
    customer_name: row.customer?.displayValue,
    service_name: row.services?.[0]?.displayValue || row.bundle?.displayValue,
    zone_name: row.zone?.displayValue,
    expires: row.expires
  });
}

// إذا عدد العناصر = حجم الصفحة → قد توجد صفحة أخرى
if (items.length >= pageSize) {
  store.currentPage++;
  return [{
    json: {
      hasMore: true,
      access_token: token,
      fromExpirationDate: $('Calculate Date Range').first().json.fromExpirationDate,
      toExpirationDate: $('Calculate Date Range').first().json.toExpirationDate,
      pageNumber: store.currentPage,
      pageSize: pageSize,
      batch: batch
    }
  }];
}

// انتهت الصفحات — إخراج كل المشتركين
console.log(`📊 إجمالي المشتركين: ${store.subscribers.length}`);
const allSubs = store.subscribers.map(s => ({ json: { ...s, batch, access_token: token } }));
store.subscribers = [];
store.currentPage = null;
return allSubs.length > 0 ? allSubs : [];

// ═══ استخراج رقم الهاتف وتخزينه ═══
const store = $getWorkflowStaticData('global');
if (!store.readyToSend) store.readyToSend = [];
if (!store.stats) store.stats = { total: 0, withPhone: 0, noPhone: 0, sent: 0, failed: 0 };

const prevData = $('Split For Phone Lookup').first().json;
const phoneData = $input.first().json;

const phone = phoneData.model?.primaryContact?.mobile || '';
const customerName = prevData.customer_name || '';
const serviceName = prevData.service_name || '';
const zoneName = prevData.zone_name || '';
const expires = prevData.expires || '';
const batch = prevData.batch;

store.stats.total++;

// تنظيف وتنسيق الرقم
let cleanPhone = phone.replace(/[^\d]/g, '');
if (cleanPhone.startsWith('0')) {
  cleanPhone = '964' + cleanPhone.substring(1);
} else if (!cleanPhone.startsWith('964')) {
  cleanPhone = '964' + cleanPhone;
}

const valid = /^964\d{9,12}$/.test(cleanPhone) && cleanPhone.length >= 12;

if (valid) {
  store.stats.withPhone++;
  store.readyToSend.push({
    phone: cleanPhone,
    name: customerName,
    service: serviceName,
    zone: zoneName,
    expires: expires,
    batch: batch
  });
} else {
  store.stats.noPhone++;
}

return [{ json: { processed: store.stats.total } }];

// ═══ إخراج المشتركين الجاهزين للإرسال ═══
const store = $getWorkflowStaticData('global');
const readyToSend = store.readyToSend || [];
const stats = store.stats || {};

console.log(`📊 الإحصائيات:`);
console.log(`   الكل: ${stats.total}`);
console.log(`   لديهم رقم: ${stats.withPhone}`);
console.log(`   بدون رقم: ${stats.noPhone}`);

if (readyToSend.length === 0) {
  console.log('⚠️ لا يوجد مشتركين للإرسال');
  // تنظيف
  store.readyToSend = [];
  return [];
}

const result = readyToSend.map(r => ({ json: r }));
store.readyToSend = []; // تنظيف
return result;

// ═══ حساب تاريخ الانتهاء وتجهيز البيانات ═══
const item = $json;
const expires = item.expires || '';
const config = $('Configuration').first().json;

let endDate = '';

try {
  const expDate = new Date(expires);
  endDate = `${expDate.getFullYear()}-${String(expDate.getMonth()+1).padStart(2,'0')}-${String(expDate.getDate()).padStart(2,'0')}`;
} catch(e) {
  endDate = expires;
}

return [{
  json: {
    phone: item.phone,
    name: item.name,
    endDate: endDate,
    contactNumbers: config.contactNumbers || '07705210210',
    batch: item.batch
  }
}];

// ═══ تتبع النتائج ═══
const store = $getWorkflowStaticData('global');
if (!store.stats) store.stats = { total: 0, withPhone: 0, noPhone: 0, sent: 0, failed: 0 };

const response = $json;
const prevData = $('Prepare Message Data').first().json;
const sent = !!(response.messages && response.messages.length > 0);

if (sent) {
  store.stats.sent++;
  console.log(`✅ ${prevData.name}: تم الإرسال`);
} else {
  store.stats.failed++;
  console.log(`❌ ${prevData.name}: فشل - ${response.error?.message || 'خطأ'}`);
}

return [{ json: { status: sent ? 'sent' : 'failed', sent: sent, phone: prevData.phone, name: prevData.name } }];

const d = $input.first().json;
const prevData = $('Prepare Message Data').first().json;
const name = prevData.name || '';
const endDate = prevData.endDate || '';
const contact = prevData.contactNumbers || '07705210210';

const msg = '\u0639\u0632\u064a\u0632\u064a \u0627\u0644\u0645\u0634\u062a\u0631\u0643 ' + name + '\n\u0627\u0634\u062a\u0631\u0627\u0643\u0643 \u0633\u064a\u0646\u062a\u0647\u064a \u0628\u062a\u0627\u0631\u064a\u062e ' + endDate + '\n\u062c\u062f\u062f \u0627\u0644\u0622\u0646!\n\n\u0644\u0644\u0627\u062a\u0635\u0627\u0644:\n' + contact;

return [{ json: {
  phone: prevData.phone,
  sent: d.sent,
  apiBody: { message: msg, type: 'template' }
} }];

// ═══ تقرير نهائي + حفظ في Firestore ═══
const store = $getWorkflowStaticData('global');
const stats = store.stats || { total: 0, withPhone: 0, noPhone: 0, sent: 0, failed: 0 };
const batch = $('Filter Already Sent').first().json;

// حساب الوقت بتوقيت بغداد
const now = new Date();
const baghdadOffset = 3 * 60;
const baghdadNow = new Date(now.getTime() + (baghdadOffset + now.getTimezoneOffset()) * 60000);
const timeStr = `${String(baghdadNow.getHours()).padStart(2,'0')}:${String(baghdadNow.getMinutes()).padStart(2,'0')}`;
const dateStr = `${baghdadNow.getFullYear()}-${String(baghdadNow.getMonth()+1).padStart(2,'0')}-${String(baghdadNow.getDate()).padStart(2,'0')}`;

const report = {
  batchId: batch.id,
  total: stats.total,
  withPhone: stats.withPhone,
  noPhone: stats.noPhone,
  sent: stats.sent,
  failed: stats.failed,
  time: timeStr,
  date: dateStr,
  days: batch.days
};

console.log('📊 التقرير النهائي:');
console.log(`   المشتركين: ${stats.total}`);
console.log(`   أرسل: ${stats.sent}`);
console.log(`   فشل: ${stats.failed}`);

// تنظيف
store.stats = null;

return [{
  json: {
    report,
    batch,
    message: `📊 *تقرير التذكير التلقائي*\n\n📅 ${dateStr} - ${timeStr}\n🔔 وجبة: ${batch.days === 0 ? 'المنتهي اليوم' : batch.days === 1 ? 'المنتهي غداً' : 'المنتهي خلال ' + batch.days + ' أيام'}\n\n🔢 المشتركين: *${stats.total}*\n📱 لديهم رقم: *${stats.withPhone}*\n✅ أرسل بنجاح: *${stats.sent}*\n❌ فشل: *${stats.failed}*\n\n🏢 _نظام شركة الصدارة_`
  }
}];
